// Date Formatter - Calculate all date formats needed for the workflow
const now = new Date();
const mountainTime = new Date(now.toLocaleString("en-US", {timeZone: "America/Denver"}));
const yesterday = new Date(mountainTime.getTime() - 24*60*60*1000);

try {
  const output = {
    today: mountainTime.toLocaleDateString('en-US', { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    }),
    dayOfWeek: mountainTime.toLocaleDateString('en-US', { weekday: 'long' }),
    usccbDate: [
      String(mountainTime.getMonth() + 1).padStart(2, '0'),
      String(mountainTime.getDate()).padStart(2, '0'), 
      String(mountainTime.getFullYear()).slice(-2)
    ].join(''),
    yesterdayMLB: yesterday.toISOString().split('T')[0],
    todayMLB: mountainTime.toISOString().split('T')[0],
    monthDay: `${mountainTime.getMonth() + 1}/${mountainTime.getDate()}`,
    yesterdayMonthDay: `${yesterday.getMonth() + 1}/${yesterday.getDate()}`,
    theme: {
      'Sunday': 'Worship & Community',
      'Monday': 'Humility & Simplicity',
      'Tuesday': 'Stability',
      'Wednesday': 'Listening',
      'Thursday': 'Hospitality & Kindness',
      'Friday': 'Sacrifice & Repentance',
      'Saturday': 'Rest & Beauty'
    }[mountainTime.toLocaleDateString('en-US', { weekday: 'long' })]
  };

  console.log('Date formatting complete:', output.today);
  console.log('Month/Day format:', output.monthDay);

  return output;

} catch (error) {
  console.error('Date formatting error:', error.message);
  return {
    today: 'Date unavailable',
    dayOfWeek: 'Today',
    theme: 'Prayer',
    monthDay: '1/1',
    usccbDate: '010125'
  };
}

// Saints Lookup - Use existing saints database
const dateInfo = $json;

try {
  const saintsDatabase = {
    '1/1': { name: 'Mary, Mother of God', type: 'Solemnity', quote: 'My soul proclaims the greatness of the Lord.', intro: 'The Solemnity of Mary, the Holy Mother of God, celebrates Mary\'s divine motherhood and her role in salvation history.' },
    '8/24': { name: 'Bartholomew', type: 'Feast', quote: 'Rabbi, you are the Son of God! You are the King of Israel!', intro: 'One of the twelve apostles, also called Nathanael, traditionally martyred in Armenia.' },
    '8/26': { name: 'Daily Weekday', type: 'Weekday', quote: 'Be it done unto me according to your word.', intro: 'Today we focus on living out our baptismal call in ordinary circumstances.' },
    '8/27': { name: 'Monica', type: 'Memorial', quote: 'Nothing is far from God.', intro: 'Mother of St. Augustine, she prayed for her son\'s conversion for many years before seeing it fulfilled.' }
  };

  const currentDate = dateInfo.monthDay;
  const todaySaint = saintsDatabase[currentDate];

  let saint = {};
  if (todaySaint) {
    saint = todaySaint;
  } else if (dateInfo.dayOfWeek === 'Sunday') {
    saint = {
      name: `${dateInfo.dayOfWeek} in Ordinary Time`,
      type: 'Sunday',
      intro: 'The Lord\'s Day, when we gather as a community to celebrate the Eucharist and commemorate Christ\'s resurrection.'
    };
  } else {
    saint = {
      name: 'Weekday in Ordinary Time',
      type: 'Weekday',
      intro: 'A day to grow in holiness through ordinary work and prayer.'
    };
  }

  return {
    ...dateInfo,
    saint: saint
  };

} catch (error) {
  console.error('Saints lookup error:', error.message);
  return {
    ...dateInfo,
    saint: {
      name: 'Daily Saint',
      type: 'Weekday',
      intro: 'Saint information unavailable'
    }
  };
}

