// Final Email Compiler - Now gets data from AI node
const aiData = $json; // AI response
const allInputs = $input.all(); // All previous data

try {
  console.log('=== EMAIL COMPILER WITH AI START ===');
  console.log('AI data keys:', Object.keys(aiData));
  console.log('Number of inputs:', allInputs.length);

  // Get the workflow data from the first input (should contain all our date/saint/readings data)
  const workflowData = allInputs[0]?.json || {};
  console.log('Workflow data keys:', Object.keys(workflowData));
  console.log('Has readings:', !!workflowData.readings);

  // Extract all the data
  const dateInfo = {
    today: workflowData.today || 'Today',
    dayOfWeek: workflowData.dayOfWeek || 'Today',
    theme: workflowData.theme || 'Prayer'
  };

  const saintData = workflowData.saint || {
    name: 'Daily Saint',
    intro: 'Saint information unavailable'
  };

  const readingsData = workflowData.readings || {
    firstReading: 'Scripture reading unavailable',
    gospel: 'Gospel reading unavailable',
    psalm: 'Psalm unavailable',
    usccbLink: 'https://bible.usccb.org'
  };

  // Parse AI spiritual content
  let spiritual = {};
  try {
    const aiText = aiData?.text || aiData?.message || aiData?.output || '';

    if (aiText) {
      const cleanText = aiText.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();
      spiritual = JSON.parse(cleanText);
      console.log('✅ Successfully parsed AI spiritual content');
    } else {
      throw new Error('No AI content available');
    }
  } catch (parseError) {
    console.log('Using fallback spiritual content:', parseError.message);
    spiritual = {
      saintIntro: saintData.intro || 'Saint information available in database',
      reflection: `Today's theme is ${dateInfo.theme}. Take time to reflect on this Benedictine virtue.`,
      challenge: 'Spend 10 minutes in silent prayer today, listening for God\'s voice.',
      prayer: 'Lord, help us follow the example of the saints and grow in holiness. Amen.',
      historicalFacts: [{year: "2024", fact: "Historical facts unavailable"}]
    };
  }

  // Ensure prayer exists and is a string
  if (!spiritual.prayer || typeof spiritual.prayer !== 'string') {
    spiritual.prayer = 'Lord, bless this day and help us grow closer to You. Amen.';
  }

  // Create enhanced email with AI content
  const subject = `Daily Reflection - ${dateInfo.today}`;

  const html = `
<!DOCTYPE html>
<html>
<head><title>${subject}</title></head>
<body style="font-family: Georgia, serif; max-width: 600px; margin: 0 auto; padding: 20px;">
  <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px 20px; text-align: center; border-radius: 8px 8px 0 0;">
    <h1 style="margin: 0; font-size: 28px; font-weight: normal;">${subject}</h1>
    <p style="margin: 10px 0 0 0; font-size: 18px; opacity: 0.95;">${dateInfo.today}</p>
    <p style="margin: 5px 0 0 0; font-size: 14px; opacity: 0.9;">Theme: ${dateInfo.theme}</p>
  </div>

  <div style="padding: 30px 25px; background: white;">

    <!-- Saint of the Day -->
    ${saintData.name !== 'Weekday in Ordinary Time' ? `
    <div style="margin-bottom: 35px;">
      <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px;">✝️ Saint of the Day</h2>
      <div style="background: #fef5e7; padding: 20px; border-radius: 8px;">
        <h3 style="margin: 0 0 10px 0; color: #764ba2; font-size: 18px;">${saintData.name}</h3>
        <p style="margin: 0; color: #4a5568; line-height: 1.7;">${spiritual.saintIntro || saintData.intro}</p>
        ${saintData.quote ? `<p style="margin: 15px 0 0 0; color: #553c9a; font-style: italic;">"${saintData.quote}"</p>` : ''}
      </div>
    </div>
    ` : ''}

    <!-- Readings Section -->
    <div style="margin-bottom: 35px;">
      <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px;">📖 Today's Readings</h2>
      <div style="background: #f7fafc; padding: 20px; border-radius: 8px;">
        <ul style="list-style: none; padding: 0; margin: 0;">
          <li style="margin: 12px 0;"><strong style="color: #2d3748;">First Reading:</strong> ${readingsData.firstReading}</li>
          <li style="margin: 12px 0;"><strong style="color: #2d3748;">Psalm:</strong> ${readingsData.psalm}</li>
          ${readingsData.secondReading ? `<li style="margin: 12px 0;"><strong style="color: #2d3748;">Second Reading:</strong> ${readingsData.secondReading}</li>` : ''}
          <li style="margin: 12px 0;"><strong style="color: #2d3748;">Gospel:</strong> ${readingsData.gospel}</li>
        </ul>
        <p style="text-align: center; margin-top: 20px;">
          <a href="${readingsData.usccbLink}" style="background: #667eea; color: white; padding: 12px 25px; text-decoration: none; border-radius: 6px; font-weight: 600;">Read Full Texts at USCCB.org →</a>
        </p>
      </div>
    </div>

    <!-- Benedictine Reflection -->
    <div style="margin-bottom: 35px;">
      <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px;">🕊️ Benedictine Reflection: ${dateInfo.theme}</h2>
      <div style="background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%); padding: 20px; border-radius: 8px;">
        <p style="margin: 0 0 15px 0; color: #4a5568; line-height: 1.7;">${spiritual.reflection}</p>
        <div style="background: rgba(255,255,255,0.7); padding: 15px; border-radius: 6px;">
          <h4 style="margin: 0 0 8px 0; color: #764ba2; font-size: 14px; text-transform: uppercase; letter-spacing: 1px;">Today's Challenge</h4>
          <p style="margin: 0; color: #4a5568; line-height: 1.6; font-weight: 500;">${spiritual.challenge}</p>
        </div>
      </div>
    </div>

    <!-- Prayer -->
    <div style="margin-bottom: 35px;">
      <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px;">🙏 Prayer for Today</h2>
      <div style="text-align: center; padding: 20px; background: #faf5ff; border-radius: 8px;">
        <p style="margin: 0; color: #553c9a; line-height: 1.8; font-size: 15px; font-style: italic;">${spiritual.prayer.replace(/\n/g, '<br/>')}</p>
      </div>
    </div>

    <!-- Historical Facts -->
    ${spiritual.historicalFacts && spiritual.historicalFacts.length > 0 ? `
    <div style="margin-bottom: 35px;">
      <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px;">📅 On This Day in History</h2>
      <ul style="margin: 0; padding: 0; list-style: none;">
        ${spiritual.historicalFacts.map(h => `
        <li style="margin-bottom: 10px; padding-left: 60px; position: relative; color: #4a5568; line-height: 1.6;">
          <span style="position: absolute; left: 0; color: #667eea; font-weight: bold; width: 50px;">${h.year}:</span>
          ${h.fact}
        </li>`).join('')}
      </ul>
    </div>
    ` : ''}

  </div>

  <footer style="background: #f7fafc; padding: 25px; text-align: center; border-top: 1px solid #e2e8f0; color: #718096; border-radius: 0 0 8px 8px;">
    <p style="margin: 0; font-size: 16px; font-style: italic; line-height: 1.6;">"Always we begin again"<br/><span style="font-size: 14px; font-style: normal;">- St. Benedict</span></p>
    <p style="margin: 15px 0 0 0; font-size: 12px; opacity: 0.7;">Daily Reflection • Catholic Spirituality • AI Enhanced</p>
  </footer>
</body>
</html>
`;

  console.log('Email compilation with AI complete');

  return {
    subject: subject,
    html: html,
    text: subject
  };

} catch (error) {
  console.error('Email compilation error:', error.message);
  return {
    subject: 'Daily Reflection - Error',
    html: `<p>Error compiling email: ${error.message}</p>`,
    text: 'Error compiling daily reflection'
  };
}
